    });

    var axY = PAD_T + entities.length * ROW_H + 14;
    el('line', { x1: PAD_L, y1: axY, x2: W - PAD_R, y2: axY, stroke: 'var(--border2,#ccc)', 'stroke-width': '1' }, g);
    var span = maxY - minY;
    var step = span <= 5 ? 1 : span <= 15 ? 2 : span <= 30 ? 5 : 10;
    for (var yr = minY; yr <= maxY; yr++) {
      var xyr = xOf(yr);
      if (xyr < PAD_L - 1 || xyr > W - PAD_R + 1) continue;
      el('line', { x1: xyr, y1: axY, x2: xyr, y2: axY + (yr % step === 0 ? 6 : 3), stroke: 'var(--border2,#ccc)', 'stroke-width': '1' }, g);
      if (yr % step === 0) tx('text', { x: xyr, y: axY + 16, 'text-anchor': 'middle', 'font-size': '10', fill: 'var(--text3,#999)' }, '' + yr, g);
    }

    var act = {};
    events.forEach(function(ev) { [ev.source, ev.target].forEach(function(ent) { if (!ent || yOf(ent) < 0) return; if (!act[ent]) act[ent] = {}; act[ent][ev.year] = (act[ent][ev.year] || 0) + ev.value; }); });
    var maxAct = 1;
    Object.keys(act).forEach(function(ent) { Object.keys(act[ent]).forEach(function(yr) { if (act[ent][yr] > maxAct) maxAct = act[ent][yr]; }); });
    entities.forEach(function(name) {
      var y = yOf(name);
      var m = act[name] || {};
      Object.keys(m).forEach(function(yr) { var cnt = m[yr]; var bh = Math.max(3, cnt / maxAct * 16); var ax = xOf(+yr); if (ax < PAD_L || ax > W - PAD_R) return; el('rect', { x: ax - 2.5, y: y - bh / 2, width: 5, height: bh, rx: '2', fill: 'var(--accent,#5470c6)', opacity: '0.3' }, g); });
    });

    var arcData = new Float32Array(events.length * 7);
    var ai = 0;
    var dup = {};
    events.forEach(function(ev) {
      var y1 = yOf(ev.source), y2 = yOf(ev.target);
      if (y1 < 0 || y2 < 0 || y1 === y2) return;
      var pk = ev.year + '|' + [ev.source, ev.target].sort().join('|');
      if (!dup[pk]) dup[pk] = 0;
      var xb = xOf(ev.year) + dup[pk] * 3; dup[pk]++;
      var ya = Math.min(y1, y2), yb = Math.max(y1, y2);
      var midY = (ya + yb) / 2;
      var r = (yb - ya) / 2;
      var sw = Math.min(6, Math.max(1.5, ev.value * 1.5));
      var rgb = hexToRgb(ev.category ? cCol(ev.category) : '#888888');
      arcData[ai++] = xb; arcData[ai++] = midY; arcData[ai++] = r; arcData[ai++] = sw;
      arcData[ai++] = rgb[0]; arcData[ai++] = rgb[1]; arcData[ai++] = rgb[2];
    });
    var arcView = ai === arcData.length ? arcData : arcData.subarray(0, ai);

    if (!glCanvas) {
      glCanvas = document.createElement('canvas');
      glCanvas.style.cssText = 'position:absolute;left:0;top:0;pointer-events:none;z-index:2;';
    }
    glCanvas.style.width = fullW + 'px';
    glCanvas.style.height = fullH + 'px';
    svgWrap.appendChild(glCanvas);

    if (!glReady && !glFailed) {
      glReady = initGL(glCanvas);
      if (!glReady) glFailed = true;
    }

    if (glFailed) {
      var fb = document.createElement('div');
      fb.style.cssText = 'position:absolute;left:0;right:0;top:8px;text-align:center;font-size:11px;color:#c33;z-index:3;pointer-events:none;';
      fb.textContent = 'WebGL unavailable — arcs not rendered. Use chart type "timearcs" instead.';
      svgWrap.appendChild(fb);
    } else {
      uploadInstances(arcView);
    }

    var zoom = { scale: 1, tx: 0, ty: 0 };
    var drag = { active: false, sx: 0, sy: 0, stx: 0, sty: 0 };
    var applyT = function() {
      g.setAttribute('transform', 'translate(' + zoom.tx + ',' + zoom.ty + ') scale(' + zoom.scale + ')');
      drawGL(zoom.tx, zoom.ty, zoom.scale);
    };
    applyT();

    svg.addEventListener('wheel', function(e) { e.preventDefault(); var f = e.deltaY < 0 ? 1.12 : 0.89; var rect = svg.getBoundingClientRect(); var mx = e.clientX - rect.left, my = e.clientY - rect.top; zoom.tx = mx + (zoom.tx - mx) * f; zoom.ty = my + (zoom.ty - my) * f; zoom.scale *= f; applyT(); }, { passive: false });
    svg.addEventListener('mousedown', function(e) { drag.active = true; drag.sx = e.clientX; drag.sy = e.clientY; drag.stx = zoom.tx; drag.sty = zoom.ty; svg.style.cursor = 'grabbing'; e.preventDefault(); });
    svg.addEventListener('mousemove', function(e) { if (!drag.active) return; zoom.tx = drag.stx + (e.clientX - drag.sx); zoom.ty = drag.sty + (e.clientY - drag.sy); applyT(); });
    svg.addEventListener('mouseup', function() { drag.active = false; svg.style.cursor = 'grab'; });
    svg.addEventListener('mouseleave', function() { drag.active = false; svg.style.cursor = 'grab'; });
    svg.addEventListener('dblclick', function() { zoom = { scale: 1, tx: 0, ty: 0 }; applyT(); });
  };

  render();
}
